     1→frappe.ui.form.on('BOM Upload', {
     2→    create_boms(frm) {
     3→        if (!frm.doc.bom_file) {
     4→            frappe.msgprint("Please attach a BOM Excel file first.");
     5→            return;
     6→        }
     7→
     8→        frappe.call({
     9→            method: 'clevertech.clevertech.doctype.bom_upload.bom_upload.create_boms',
    10→            args: {
    11→                docname: frm.doc.name
    12→            },
    13→            freeze: true,
    14→            freeze_message: __('Creating BOMs...'),
    15→            callback(r) {
    16→                if (!r.message) {
    17→                    frappe.msgprint({
    18→                        title: __('Error'),
    19→                        message: __('No response from server'),
    20→                        indicator: 'red'
    21→                    });
    22→                    return;
    23→                }
    24→
    25→                const msg = r.message;
    26→                let error_html = '';
    27→
    28→                if (msg.errors && msg.errors.length > 0) {
    29→                    error_html = '<br><br><strong>Errors:</strong><br>' + msg.errors.join('<br>');
    30→                }
    31→
    32→                frappe.msgprint({
    33→                    title: __('BOM Import Result'),
    34→                    message: `
    35→                        <strong>BOMs Created:</strong> ${msg.created}<br>
    36→                        <strong>BOMs Skipped:</strong> ${msg.skipped}<br>
    37→                        <strong>Failed:</strong> ${msg.failed}
    38→                        ${error_html}
    39→                    `,
    40→                    indicator: msg.failed > 0 ? 'orange' : 'green'
    41→                });
    42→
    43→                frm.reload_doc();
    44→            },
    45→            error(r) {
    46→                frappe.msgprint({
    47→                    title: __('Error'),
    48→                    message: __('Failed to create BOMs. Please check the error log.'),
    49→                    indicator: 'red'
    50→                });
    51→            }
    52→        });
    53→    },
    54→
    55→    create_boms_with_validation(frm) {
    56→        if (!frm.doc.bom_file) {
    57→            frappe.msgprint("Please attach a BOM Excel file first.");
    58→            return;
    59→        }
    60→
    61→        if (!frm.doc.project) {
    62→            frappe.msgprint("Please select a Project first.");
    63→            return;
    64→        }
    65→
    66→        frappe.call({
    67→            method: 'clevertech.clevertech.doctype.bom_upload.bom_upload_enhanced.create_boms_with_validation',
    68→            args: {
    69→                docname: frm.doc.name
    70→            },
    71→            freeze: true,
    72→            freeze_message: __('Analyzing BOM upload...'),
    73→            callback(r) {
    74→                if (!r.message) {
    75→                    frappe.msgprint({
    76→                        title: __('Error'),
    77→                        message: __('No response from server'),
    78→                        indicator: 'red'
    79→                    });
    80→                    return;
    81→                }
    82→
    83→                const result = r.message;
    84→
    85→                if (result.status === 'blocked') {
    86→                    _show_loose_items_blocked_dialog(result);
    87→                }
    88→                else if (result.status === 'requires_resolution') {
    89→                    _show_change_resolution_dialog(result.analysis, frm);
    90→                }
    91→                else if (result.status === 'success') {
    92→                    _show_upload_success(result);
    93→                    frm.reload_doc();
    94→                }
    95→            },
    96→            error(r) {
    97→                frappe.msgprint({
    98→                    title: __('Error'),
    99→                    message: __('Failed to process BOM upload. Check error log.'),
   100→                    indicator: 'red'
   101→                });
   102→            }
   103→        });
   104→    }
   105→});
   106→
   107→
   108→// ==================== Dialog Functions ====================
   109→
   110→function _show_loose_items_blocked_dialog(data) {
   111→    let items_html = '';
   112→    if (data.analysis && data.analysis.loose_blocked) {
   113→        items_html = data.analysis.loose_blocked.map(function(item) {
   114→            return '<li><b>' + (item.node ? item.node.item_code : 'Unknown') + '</b>'
   115→                + ' - ' + (item.details ? item.details.message : 'Conversion not enabled')
   116→                + '<br><small>Go to Project Component Master to enable conversion</small></li>';
   117→        }).join('');
   118→    }
   119→
   120→    let html = '<div class="alert alert-danger">'
   121→        + '<h5><i class="fa fa-lock"></i> Loose Items Blocking BOM Creation</h5>'
   122→        + '<p>The following loose items must have "Can be converted to BOM" enabled first:</p>'
   123→        + '<ul>' + items_html + '</ul>'
   124→        + '</div>';
   125→
   126→    frappe.msgprint({
   127→        title: __('Upload Blocked'),
   128→        message: html,
   129→        indicator: 'red',
   130→        primary_action: {
   131→            label: __('Open Component Master List'),
   132→            action: function() {
   133→                frappe.set_route('List', 'Project Component Master', {
   134→                    'is_loose_item': 1
   135→                });
   136→            }
   137→        }
   138→    });
   139→}
   140→
   141→function _show_change_resolution_dialog(analysis, frm) {
   142→    let changed_components = analysis.changed_components || [];
   143→    let blocked_components = analysis.blocked_by_dependencies || {};
   144→    let summary = analysis.summary || {};
   145→
   146→    let changed_html = '';
   147→    if (changed_components.length > 0) {
   148→        changed_html = '<div class="changed-components" style="margin-bottom:20px">'
   149→            + '<h6 class="text-warning"><i class="fa fa-exclamation-triangle"></i> Changed Components Requiring Resolution:</h6>';
   150→
   151→        changed_components.forEach(function(comp, idx) {
   152→            let node = comp.node || {};
   153→            let details = comp.details || {};
   154→            let procurement_html = '';
   155→
   156→            if (details.procurement_status && details.procurement_status.length > 0) {
   157→                procurement_html = '<div class="alert alert-warning">'
   158→                    + '<b><i class="fa fa-warning"></i> Active Procurement:</b>'
   159→                    + '<ul style="margin:5px 0 0 20px">'
   160→                    + details.procurement_status.map(function(doc) {
   161→                        return '<li>' + doc.doctype + ': ' + doc.name + ' (' + doc.status + ')</li>';
   162→                    }).join('')
   163→                    + '</ul></div>';
   164→            }
   165→
   166→            changed_html += '<div class="card mb-3" style="border-left:3px solid #ffa00a;padding:10px;margin-bottom:10px">'
   167→                + '<h6>[' + (idx + 1) + '/' + changed_components.length + '] ' + node.item_code + '</h6>'
   168→                + '<p><b>Change Type:</b> ' + (details.change_type || 'Unknown') + '</p>'
   169→                + '<p><b>Old BOM:</b> '
   170→                + (details.old_bom
   171→                    ? '<a href="/app/bom/' + details.old_bom + '">' + details.old_bom + '</a>'
   172→                    : 'None')
   173→                + '</p>'
   174→                + procurement_html
   175→                + '<p class="text-muted"><small><i class="fa fa-info-circle"></i> '
   176→                + 'Action: Deactivate old BOM manually, then re-run upload</small></p>'
   177→                + '</div>';
   178→        });
   179→
   180→        changed_html += '</div>';
   181→    }
   182→
   183→    let blocked_html = '';
   184→    let blocked_keys = Object.keys(blocked_components);
   185→    if (blocked_keys.length > 0) {
   186→        blocked_html = '<div class="blocked-components">'
   187→            + '<h6 class="text-danger"><i class="fa fa-ban"></i> Components Blocked by Dependencies:</h6>'
   188→            + '<ul>';
   189→
   190→        blocked_keys.forEach(function(item) {
   191→            let reasons = blocked_components[item] || [];
   192→            blocked_html += '<li><b>' + item + '</b><ul style="margin-left:20px">';
   193→            reasons.forEach(function(r) {
   194→                blocked_html += '<li>' + r.item + ': ' + r.reason + '</li>';
   195→            });
   196→            blocked_html += '</ul></li>';
   197→        });
   198→
   199→        blocked_html += '</ul></div>';
   200→    }
   201→
   202→    let html = '<div class="bom-change-resolution">'
   203→        + '<h5><i class="fa fa-warning"></i> BOM Upload Analysis</h5>'
   204→        + '<div class="summary" style="margin:15px 0">'
   205→        + '<table class="table table-bordered table-sm">'
   206→        + '<tr class="text-success"><td><i class="fa fa-check"></i> Can Create Immediately:</td>'
   207→        + '<td><b>' + (summary.can_create || 0) + '</b> components</td></tr>'
   208→        + '<tr class="text-warning"><td><i class="fa fa-exclamation-triangle"></i> Changed Components:</td>'
   209→        + '<td><b>' + (summary.changed || 0) + '</b> components</td></tr>'
   210→        + '<tr class="text-danger"><td><i class="fa fa-ban"></i> Blocked by Dependencies:</td>'
   211→        + '<td><b>' + (summary.blocked || 0) + '</b> components</td></tr>'
   212→        + '</table></div>'
   213→        + changed_html
   214→        + blocked_html
   215→        + '<hr>'
   216→        + '<div class="alert alert-info">'
   217→        + '<h6><i class="fa fa-lightbulb-o"></i> Next Steps:</h6>'
   218→        + '<ol style="margin:10px 0 0 20px">'
   219→        + '<li>Review changed components above</li>'
   220→        + '<li>Deactivate old BOMs in BOM List</li>'
   221→        + '<li>Re-run "Create BOMs with Validation" to complete upload</li>'
   222→        + '</ol></div>'
   223→        + '</div>';
   224→
   225→    let d = new frappe.ui.Dialog({
   226→        title: __('BOM Changes Detected - Resolution Required'),
   227→        fields: [
   228→            {
   229→                fieldtype: 'HTML',
   230→                fieldname: 'analysis_html',
   231→                options: html
   232→            }
   233→        ],
   234→        size: 'large',
   235→        primary_action_label: __('Open BOM List'),
   236→        primary_action: function() {
   237→            let item_codes = changed_components.map(function(c) {
   238→                return c.node ? c.node.item_code : '';
   239→            }).filter(function(c) { return c; });
   240→
   241→            frappe.set_route('List', 'BOM', {
   242→                'item': ['in', item_codes],
   243→                'is_active': 1
   244→            });
   245→            d.hide();
   246→        }
   247→    });
   248→
   249→    d.show();
   250→}
   251→
   252→function _show_upload_success(result) {
   253→    let errors_html = '';
   254→    if (result.errors && result.errors.length > 0) {
   255→        errors_html = '<hr><h6 class="text-danger">Errors:</h6>'
   256→            + '<ul>' + result.errors.map(function(e) { return '<li>' + e + '</li>'; }).join('') + '</ul>';
   257→    }
   258→
   259→    let html = '<div class="alert alert-success">'
   260→        + '<h5><i class="fa fa-check-circle"></i> BOM Upload Complete</h5>'
   261→        + '<table class="table table-sm" style="margin-top:15px">'
   262→        + '<tr><td><i class="fa fa-plus-circle text-success"></i> BOMs Created:</td>'
   263→        + '<td><b>' + (result.created || 0) + '</b></td></tr>'
   264→        + '<tr><td><i class="fa fa-minus-circle text-muted"></i> Skipped (Unchanged):</td>'
   265→        + '<td><b>' + (result.skipped || 0) + '</b></td></tr>'
   266→        + '<tr><td><i class="fa fa-times-circle text-danger"></i> Failed:</td>'
   267→        + '<td><b>' + (result.failed || 0) + '</b></td></tr>'
   268→        + '<tr class="text-primary"><td><i class="fa fa-cube"></i> Component Masters Created:</td>'
   269→        + '<td><b>' + (result.component_masters_created || 0) + '</b></td></tr>'
   270→        + '</table>'
   271→        + errors_html
   272→        + '</div>';
   273→
   274→    frappe.msgprint({
   275→        title: __('Success'),
   276→        message: html,
   277→        indicator: 'green'
   278→    });
